import React, { useState, useEffect, useRef } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock, 
  Zap, 
  Battery, 
  ShieldCheck, 
  ChevronRight, 
  Star, 
  Truck,
  MessageCircle,
  Menu,
  X,
  AlertTriangle,
  Heart,
  Search,
  CheckCircle2,
  Settings,
  Fuel,
  CircleDot
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { 
  RESCUE_HOTLINES, 
  SOS_WARRANTY, 
  BRANDS, 
  SERVICES, 
  BRANCHES, 
  COVERAGE_AREAS,
  LANDLINE
} from './constants';

const App: React.FC = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [activeSection, setActiveSection] = useState('home');
  const [showRescueFab, setShowRescueFab] = useState(true);
  const [aiResponse, setAiResponse] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  // Intersection Observer to handle active section highlighting
  useEffect(() => {
    const observerOptions = {
      root: null,
      rootMargin: '-20% 0px -70% 0px', // Adjust margin to trigger active state closer to the top
      threshold: 0
    };

    const handleIntersection = (entries: IntersectionObserverEntry[]) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          setActiveSection(entry.target.id);
        }
      });
    };

    const observer = new IntersectionObserver(handleIntersection, observerOptions);
    const sections = ['home', 'brands', 'services', 'locations', 'contact'];

    sections.forEach((id) => {
      const el = document.getElementById(id);
      if (el) observer.observe(el);
    });

    return () => observer.disconnect();
  }, []);

  const handleAskExpert = async (query: string) => {
    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `You are a battery expert for MP88 Battery World. 
        A customer is asking: "${query}". 
        Help them understand their battery needs. 
        If they need rescue, emphasize calling 09989996788. 
        Mention we have Motolite EFB, Delkor, ACDelco, etc. 
        Keep it professional, helpful, and concise.`,
      });
      setAiResponse(response.text);
    } catch (error) {
      console.error("AI Error:", error);
      setAiResponse("I'm sorry, I'm having trouble connecting to the specialist. Please call our hotline for immediate assistance.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const navItems = [
    { name: 'Home', id: 'home' },
    { name: 'Brands', id: 'brands' },
    { name: 'Services', id: 'services' },
    { name: 'Locations', id: 'locations' },
    { name: 'Contact', id: 'contact' }
  ];

  return (
    <div className="min-h-screen flex flex-col font-sans">
      {/* Top Banner - Emergency Info */}
      <div className="bg-red-600 text-white py-2 px-4 text-center text-sm font-bold flex items-center justify-center gap-4 overflow-hidden whitespace-nowrap">
        <div className="animate-marquee inline-block">
          🚨 24/7 BATTERY RESCUE: {RESCUE_HOTLINES[3]} / {RESCUE_HOTLINES[2]} 🚨 FREE DELIVERY & INSTALLATION IN MACTAN, CEBU, MANDAUE & MORE!
        </div>
      </div>

      {/* Navigation */}
      <nav className="sticky top-0 z-50 bg-white/95 backdrop-blur-md shadow-sm border-b transition-all">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-20">
            <div className="flex items-center">
              <a href="#home" className="flex-shrink-0 flex items-center gap-2 hover:opacity-90 transition-opacity">
                <div className="bg-yellow-400 p-2 rounded-lg font-black text-black text-xl italic border-2 border-black">
                  MP88
                </div>
                <div className="hidden sm:block">
                  <span className="text-xl font-extrabold tracking-tighter text-blue-900 block leading-none">BATTERY WORLD</span>
                  <span className="text-[10px] font-bold text-gray-500 tracking-widest uppercase">Expert Automotive Power</span>
                </div>
              </a>
            </div>

            {/* Desktop Nav */}
            <div className="hidden md:flex items-center space-x-8">
              {navItems.map((item) => (
                <a
                  key={item.id}
                  href={`#${item.id}`}
                  className={`font-semibold text-sm uppercase tracking-wider transition-all hover:text-red-600 ${
                    activeSection === item.id ? 'text-red-600 active-nav-link scale-105' : 'text-gray-600'
                  }`}
                >
                  {item.name}
                </a>
              ))}
              <a 
                href={`tel:${RESCUE_HOTLINES[3]}`}
                className="bg-red-600 text-white px-6 py-3 rounded-full font-bold text-sm flex items-center gap-2 hover:bg-red-700 transition-all shadow-lg hover:shadow-red-200"
              >
                <Zap size={18} fill="white" />
                24/7 RESCUE
              </a>
            </div>

            {/* Mobile menu button */}
            <div className="md:hidden flex items-center">
              <button
                onClick={() => setIsMenuOpen(!isMenuOpen)}
                className="p-2 rounded-md text-gray-700 hover:bg-gray-100 transition-colors"
                aria-label="Toggle Menu"
              >
                {isMenuOpen ? <X size={28} /> : <Menu size={28} />}
              </button>
            </div>
          </div>
        </div>

        {/* Mobile menu */}
        {isMenuOpen && (
          <div className="md:hidden bg-white border-b border-gray-200 py-6 px-6 space-y-4 shadow-2xl animate-in slide-in-from-top duration-300">
            {navItems.map((item) => (
              <a
                key={item.id}
                href={`#${item.id}`}
                onClick={() => setIsMenuOpen(false)}
                className={`block text-xl font-bold pb-2 transition-colors ${
                  activeSection === item.id ? 'text-red-600 border-l-4 border-red-600 pl-4' : 'text-gray-800 border-l-4 border-transparent pl-4'
                }`}
              >
                {item.name}
              </a>
            ))}
            <a 
              href={`tel:${RESCUE_HOTLINES[3]}`}
              className="block bg-red-600 text-white text-center py-4 rounded-xl font-black text-lg shadow-lg active:scale-95 transition-transform"
            >
              CALL RESCUE NOW
            </a>
          </div>
        )}
      </nav>

      <main className="flex-grow">
        {/* Hero Section */}
        <section id="home" className="relative bg-black overflow-hidden py-16 lg:py-32 scroll-mt-20">
          <div className="absolute inset-0 opacity-40">
            <img 
              src="https://images.unsplash.com/photo-1492144534655-ae79c964c9d7?auto=format&fit=crop&q=80&w=1600" 
              alt="Battery Rescue" 
              className="w-full h-full object-cover"
            />
          </div>
          <div className="absolute inset-0 bg-gradient-to-r from-black via-black/80 to-transparent"></div>

          <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-col lg:flex-row items-center">
            <div className="lg:w-3/5 text-center lg:text-left space-y-8">
              <div className="inline-flex items-center bg-yellow-400 text-black px-4 py-1.5 rounded-full font-bold text-xs uppercase tracking-widest mb-4">
                <AlertTriangle size={14} className="mr-2" /> Authorized Motolite Distributor
              </div>
              <h1 className="text-5xl lg:text-7xl font-black text-white leading-tight uppercase tracking-tighter">
                Never Get <span className="text-yellow-400">Stranded</span> Again.
              </h1>
              <p className="text-xl text-gray-300 max-w-2xl font-light">
                MP88 Battery World offers the widest selection of batteries worldwide. 24/7 Rescue, Free Delivery, and Free Installation across Cebu, Davao, and Bohol.
              </p>

              <div className="flex flex-col sm:flex-row gap-4 justify-center lg:justify-start pt-4">
                <a 
                  href={`tel:${RESCUE_HOTLINES[3]}`}
                  className="bg-yellow-400 text-black px-10 py-5 rounded-xl font-black text-lg flex items-center justify-center gap-3 hover:scale-105 transition-transform shadow-xl shadow-yellow-400/20"
                >
                  <Phone size={24} />
                  {RESCUE_HOTLINES[3]}
                </a>
                <a 
                  href="#locations"
                  className="bg-white/10 backdrop-blur-md text-white border border-white/20 px-10 py-5 rounded-xl font-bold text-lg flex items-center justify-center gap-3 hover:bg-white/20 transition-all"
                >
                  <MapPin size={24} />
                  Find Near Me
                </a>
              </div>

              <div className="grid grid-cols-2 sm:grid-cols-4 gap-6 pt-10">
                <div className="text-center sm:text-left">
                  <div className="text-yellow-400 text-3xl font-black italic tracking-tighter">100%</div>
                  <div className="text-gray-400 text-xs uppercase font-bold tracking-widest">Good Health</div>
                </div>
                <div className="text-center sm:text-left">
                  <div className="text-yellow-400 text-3xl font-black italic tracking-tighter">FREE</div>
                  <div className="text-gray-400 text-xs uppercase font-bold tracking-widest">Installation</div>
                </div>
                <div className="text-center sm:text-left">
                  <div className="text-yellow-400 text-3xl font-black italic tracking-tighter">24/7</div>
                  <div className="text-gray-400 text-xs uppercase font-bold tracking-widest">Rescue</div>
                </div>
                <div className="text-center sm:text-left">
                  <div className="text-yellow-400 text-3xl font-black italic tracking-tighter">SOS</div>
                  <div className="text-gray-400 text-xs uppercase font-bold tracking-widest">Warranty</div>
                </div>
              </div>
            </div>

            <div className="lg:w-2/5 mt-16 lg:mt-0 relative">
              <div className="bg-white p-8 rounded-3xl shadow-2xl space-y-6 max-w-sm mx-auto transform hover:-rotate-1 transition-transform">
                <div className="flex items-center gap-3 border-b pb-4">
                  <div className="w-12 h-12 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center">
                    <Battery size={24} />
                  </div>
                  <h3 className="text-xl font-extrabold text-blue-900">Expert Diagnostics</h3>
                </div>
                <ul className="space-y-4">
                  {[
                    "Battery State-of-Health Check",
                    "Alternator/Charging System Free Check",
                    "State-of-the-art Testing Tech",
                    "Dedicated Battery Specialists"
                  ].map((item, idx) => (
                    <li key={idx} className="flex items-start gap-3 text-gray-700">
                      <CheckCircle2 size={20} className="text-green-500 mt-0.5 flex-shrink-0" />
                      <span className="font-medium text-sm">{item}</span>
                    </li>
                  ))}
                </ul>
                <div className="pt-4">
                   <div className="text-xs text-gray-500 mb-2 font-bold uppercase">Ask Our Specialist</div>
                   <div className="flex gap-2">
                      <input 
                        type="text" 
                        placeholder="My car won't start..." 
                        className="flex-grow border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-yellow-400 outline-none"
                        onKeyDown={(e) => {
                          if (e.key === 'Enter') handleAskExpert((e.target as HTMLInputElement).value);
                        }}
                      />
                      <button 
                        onClick={() => handleAskExpert("What battery is best for Mazda 2?")}
                        className="bg-black text-white px-3 py-2 rounded-lg hover:bg-gray-800 transition-colors"
                      >
                        <Search size={18} />
                      </button>
                   </div>
                   {isAiLoading && <div className="mt-2 text-xs animate-pulse">Consulting specialist...</div>}
                   {aiResponse && (
                     <div className="mt-4 p-3 bg-gray-50 rounded-lg text-xs text-gray-600 border border-gray-100 leading-relaxed max-h-40 overflow-y-auto">
                        <strong>MP88 Bot:</strong> {aiResponse}
                     </div>
                   )}
                </div>
              </div>
            </div>
          </div>
        </section>

        {/* Brand Showcase */}
        <section id="brands" className="py-20 bg-gray-50 scroll-mt-20">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="text-center mb-16">
              <h2 className="text-sm font-black text-red-600 uppercase tracking-widest mb-4">World-Class Selection</h2>
              <p className="text-4xl font-extrabold text-gray-900 tracking-tight">Batteries from Around the Globe</p>
              <p className="text-gray-500 mt-4 max-w-2xl mx-auto italic">“Find it here at MP88” - Quality and Affordability Guaranteed.</p>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-6">
              {BRANDS.map((brand) => (
                <div key={brand.name} className="bg-white p-8 rounded-2xl shadow-sm border border-gray-100 flex flex-col items-center justify-center group hover:shadow-xl transition-all hover:-translate-y-1">
                  <div className="text-2xl mb-2 grayscale group-hover:grayscale-0 transition-all">{brand.flag}</div>
                  <h3 className="font-black text-lg tracking-tighter text-gray-800 group-hover:text-red-600 transition-colors">{brand.name}</h3>
                  <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">{brand.origin}</p>
                </div>
              ))}
              <div className="bg-red-600 p-8 rounded-2xl shadow-xl flex flex-col items-center justify-center text-white">
                <h3 className="font-black text-xl italic">& MORE...</h3>
                <p className="text-[10px] uppercase font-bold opacity-80 mt-2 text-red-100">Widest Inventory</p>
              </div>
            </div>
          </div>
        </section>

        {/* Services Section */}
        <section id="services" className="py-20 bg-white scroll-mt-20">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex flex-col md:flex-row md:items-end justify-between mb-16 gap-8">
              <div className="max-w-2xl">
                <h2 className="text-sm font-black text-red-600 uppercase tracking-widest mb-4">What We Do</h2>
                <p className="text-4xl font-extrabold text-gray-900 tracking-tight">Beyond Just Batteries</p>
                <p className="text-gray-500 mt-4">We provide comprehensive roadside assistance and automotive electrical services 24 hours a day, 7 days a week.</p>
              </div>
              <div className="flex items-center gap-4 bg-gray-50 p-4 rounded-2xl border border-gray-100">
                <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center text-red-600">
                  <ShieldCheck size={28} />
                </div>
                <div>
                  <div className="font-black text-sm uppercase text-gray-900">SOS Warranty</div>
                  <div className="text-xs text-gray-500 tracking-tight font-medium">Secured Our Service #{SOS_WARRANTY}</div>
                </div>
              </div>
            </div>

            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
              {SERVICES.map((svc) => (
                <div key={svc.id} className="group p-8 rounded-3xl border-2 border-transparent hover:border-red-600 hover:bg-gray-50 transition-all duration-300">
                  <div className="w-16 h-16 bg-red-600 text-white rounded-2xl flex items-center justify-center mb-8 shadow-lg group-hover:scale-110 transition-transform">
                    {svc.id === 'rescue' && <Zap size={32} />}
                    {svc.id === 'install' && <Settings size={32} />}
                    {svc.id === 'tradein' && <Battery size={32} />}
                    {svc.id === 'jumpstart' && <Zap size={32} />}
                    {svc.id === 'gasup' && <Fuel size={32} />}
                    {svc.id === 'vulcanizing' && <CircleDot size={32} />}
                  </div>
                  <h3 className="text-2xl font-black text-gray-900 mb-3">{svc.title}</h3>
                  <p className="text-gray-600 leading-relaxed font-medium">{svc.description}</p>
                  <a href={`tel:${RESCUE_HOTLINES[3]}`} className="mt-6 inline-flex items-center gap-2 text-red-600 font-bold uppercase text-xs tracking-widest cursor-pointer group-hover:gap-4 transition-all">
                    Inquire Now <ChevronRight size={16} />
                  </a>
                </div>
              ))}
            </div>
          </div>
        </section>

        {/* Locations Grid */}
        <section id="locations" className="py-20 bg-gray-50 scroll-mt-20">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
             <div className="text-center mb-16">
              <h2 className="text-sm font-black text-red-600 uppercase tracking-widest mb-4">Branch Network</h2>
              <p className="text-4xl font-extrabold text-gray-900 tracking-tight">Visit Us Nationwide</p>
              <div className="mt-6 flex flex-wrap justify-center gap-2">
                {['Mactan', 'Cebu', 'Tagbilaran', 'Mandaue', 'Dapitan', 'Dipolog', 'Davao'].map(loc => (
                  <span key={loc} className="px-3 py-1 bg-white border rounded-full text-xs font-bold text-gray-500">| {loc} |</span>
                ))}
              </div>
            </div>

            <div className="grid md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {BRANCHES.map((branch, idx) => (
                <div key={idx} className="bg-white p-6 rounded-3xl shadow-sm border hover:shadow-xl transition-all flex flex-col h-full group">
                  <div className="flex justify-between items-start mb-4">
                    <h3 className="font-black text-gray-900 tracking-tighter leading-tight text-lg group-hover:text-red-600 transition-colors">{branch.name}</h3>
                    <span className="bg-red-50 text-red-600 text-[10px] font-black uppercase px-2 py-1 rounded-md">{branch.location}</span>
                  </div>
                  <p className="text-xs text-gray-500 mb-6 flex-grow leading-relaxed">{branch.address}</p>
                  <div className="space-y-3 mt-auto pt-6 border-t">
                    <div className="flex items-center gap-2 text-xs font-bold text-gray-700">
                      <Clock size={16} className="text-red-500" />
                      {branch.hours}
                    </div>
                    <a 
                      href={`tel:${branch.phone}`}
                      className="flex items-center gap-2 text-xs font-bold text-blue-600 hover:text-blue-800 transition-colors"
                    >
                      <Phone size={16} className="text-blue-500" />
                      {branch.phone}
                    </a>
