import React, { useState, useEffect, useRef } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock, 
  Zap, 
  Battery, 
  ShieldCheck, 
  ChevronRight, 
  Star, 
  Truck,
  MessageCircle,
  Menu,
  X,
  AlertTriangle,
  Heart,
  Search,
  CheckCircle2,
  Settings,
  Fuel,
  CircleDot
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { 
  RESCUE_HOTLINES, 
  SOS_WARRANTY, 
  BRANDS, 
  SERVICES, 
  BRANCHES, 
  COVERAGE_AREAS,
  LANDLINE
} from './constants';

const App: React.FC = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [activeSection, setActiveSection] = useState('home');
  const [isScrolled, setIsScrolled] = useState(false);
  const [showRescueFab, setShowRescueFab] = useState(true);
  const [aiResponse, setAiResponse] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  // Handle scroll events for navbar appearance (Sticky behavior)
  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Intersection Observer to handle active section highlighting
  useEffect(() => {
    const observerOptions = {
      root: null,
      rootMargin: '-40% 0px -40% 0px', // Trigger when section is roughly in the middle
      threshold: 0
    };

    const handleIntersection = (entries: IntersectionObserverEntry[]) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          setActiveSection(entry.target.id);
        }
      });
    };

    const observer = new IntersectionObserver(handleIntersection, observerOptions);
    const sections = ['home', 'brands', 'services', 'locations', 'contact'];

    sections.forEach((id) => {
      const el = document.getElementById(id);
      if (el) observer.observe(el);
    });

    return () => observer.disconnect();
  }, []);

