import React, { useState, useEffect, useCallback } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock, 
  Zap, 
  Battery, 
  ShieldCheck, 
  ChevronRight, 
  Star, 
  Menu,
  X,
  AlertTriangle,
  Search,
  CheckCircle2,
  Settings,
  Fuel,
  CircleDot,
  Mail,
  Send,
  MessageCircle,
  Facebook
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { 
  RESCUE_HOTLINES, 
  SOS_WARRANTY, 
  BRANDS, 
  SERVICES, 
  BRANCHES, 
  LANDLINE
} from './constants';

const App: React.FC = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [activeSection, setActiveSection] = useState('home');
  const [isScrolled, setIsScrolled] = useState(false);
  const [showRescueFab, setShowRescueFab] = useState(true);
  const [aiResponse, setAiResponse] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  // Enhanced Scroll Logic to handle fixed header offset
  const scrollToSection = useCallback((id: string) => {
    const element = document.getElementById(id);
    if (element) {
      // The fixed header is roughly 80px high
      const headerOffset = 80;
      const elementPosition = element.getBoundingClientRect().top;
      const offsetPosition = elementPosition + window.pageYOffset - headerOffset;

      window.scrollTo({
        top: offsetPosition,
        behavior: 'smooth'
      });

      setActiveSection(id);
      setIsMenuOpen(false);
      // Update URL hash without jarring jump
      window.history.pushState(null, '', `#${id}`);
    }
  }, []);

  // Sync scroll position for navbar styling
  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // High-precision scroll spy (Intersection Observer)
  useEffect(() => {
    const observerOptions = {
      root: null,
      // Adjust margins to trigger when section reaches the header area
      rootMargin: '-85px 0px -70% 0px',
      threshold: 0
    };

    const handleIntersection = (entries: IntersectionObserverEntry[]) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          setActiveSection(entry.target.id);
        }
      });
    };

    const observer = new IntersectionObserver(handleIntersection, observerOptions);
    const sections = ['home', 'brands', 'services', 'locations', 'contact'];

    sections.forEach((id) => {
      const el = document.getElementById(id);
      if (el) observer.observe(el);
    });

    return () => observer.disconnect();
  }, []);

  const handleAskExpert = async (query: string) => {
    if (!query.trim()) return;
    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `You are a battery expert for MP88 Battery World. 
        A customer is asking: "${query}". 
        Help them understand their battery needs. 
        If they need rescue, emphasize calling 09989996788. 
        Mention we have Motolite EFB, Delkor, ACDelco, Amaron, and GS. 
        Mention 24/7 rescue service and free installation.
        Keep it professional, helpful, and concise.`,
      });
      setAiResponse(response.text);
    } catch (error) {
      console.error("AI Error:", error);
      setAiResponse("I'm sorry, I'm having trouble connecting to the specialist. Please call our hotline at 09989996788 for immediate assistance.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const navItems = [
    { name: 'Home', id: 'home' },
    { name: 'Brands', id: 'brands' },
    { name: 'Services', id: 'services' },
    { name: 'Locations', id: 'locations' },
    { name: 'Contact', id: 'contact' }
  ];

  const handleLinkClick = (e: React.MouseEvent<HTMLAnchorElement>, id: string) => {
    e.preventDefault();
    scrollToSection(id);
  };

  return (
    <div className="min-h-screen flex flex-col font-sans selection:bg-red-100 selection:text-red-900 overflow-x-hidden">
      {/* Fixed Emergency Banner */}
      <div className="fixed top-0 inset-x-0 z-[70] bg-red-600 text-white py-1.5 px-4 text-center text-[10px] sm:text-xs font-black flex items-center justify-center gap-4 overflow-hidden shadow-lg">
        <div className="animate-marquee whitespace-nowrap">
          🚨 24/7 BATTERY RESCUE: {RESCUE_HOTLINES[3]} / {RESCUE_HOTLINES[2]} 🚨 FREE DELIVERY & INSTALLATION IN MACTAN, CEBU, MANDAUE & MORE! 🚨 LANDLINE: {LANDLINE} 🚨
        </div>
      </div>

      {/* Persistence Navigation Bar */}
      <nav className={`fixed top-[28px] inset-x-0 z-[60] transition-all duration-500 ease-in-out ${
        isScrolled ? 'bg-white/95 backdrop-blur-md shadow-2xl py-0' : 'bg-white/90 py-1'
      } border-b border-gray-100`}>
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className={`flex justify-between items-center transition-all duration-500 ${isScrolled ? 'h-16' : 'h-20'}`}>
            <div className="flex items-center">
              <a 
                href="#home" 
                onClick={(e) => handleLinkClick(e, 'home')} 
                className="flex-shrink-0 flex items-center gap-2 group transition-transform hover:scale-[1.02]"
              >
                <div className="bg-yellow-400 p-2 rounded-lg font-black text-black text-xl italic border-2 border-black shadow-[2px_2px_0px_0px_rgba(0,0,0,1)] group-hover:shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] transition-all">
                  MP88
                </div>
                <div className="hidden sm:block">
                  <span className="text-xl font-extrabold tracking-tighter text-blue-900 block leading-none">BATTERY WORLD</span>
                  <span className="text-[10px] font-bold text-gray-500 tracking-widest uppercase">Expert Automotive Power</span>
                </div>
              </a>
            </div>

            {/* Desktop Nav - Follows Scroll Spy */}
            <div className="hidden md:flex items-center space-x-8 lg:space-x-10">
              {navItems.map((item) => (
                <a
