import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock, 
  Zap, 
  Battery, 
  ShieldCheck, 
  ChevronRight, 
  Star, 
  Menu,
  X,
  AlertTriangle,
  CheckCircle2,
  Settings,
  Fuel,
  CircleDot,
  Facebook,
  ExternalLink,
  MessageSquare
} from 'lucide-react';
