import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  Phone, 
  MapPin, 
  Clock, 
  Zap, 
  Battery, 
  ShieldCheck, 
  ChevronRight, 
  Star, 
  Menu,
  X,
  AlertTriangle,
  CheckCircle2,
  Settings,
  Fuel, 
  CircleDot,
  Facebook,
  ExternalLink,
  MessageSquare
} from 'lucide-react';
import { 
  RESCUE_HOTLINES, 
  SOS_WARRANTY, 
  BRANDS, 
  SERVICES, 
  BRANCHES, 
  LANDLINE
} from './constants';

const App: React.FC = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [activeSection, setActiveSection] = useState('home');
  const [isScrolled, setIsScrolled] = useState(false);
  const [showRescueFab, setShowRescueFab] = useState(true);
  const [selectedLocation, setSelectedLocation] = useState<string>('All');

  const locationCategories = useMemo(() => ['All', 'Mactan', 'Cebu', 'Tagbilaran', 'Mandaue', 'Dapitan', 'Dipolog', 'Davao'], []);

  const filteredBranches = useMemo(() => {
    if (selectedLocation === 'All') return BRANCHES;
    return BRANCHES.filter(branch => {
      // Logic for Dipolog / Dapitan combined entry
      if (selectedLocation === 'Dapitan' || selectedLocation === 'Dipolog') {
        return (
          branch.location === 'Dipolog' || 
          branch.location === 'Dapitan' || 
          branch.name.toUpperCase().includes('DIPOLOG') || 
          branch.name.toUpperCase().includes('DAPITAN')
        );
      }
      return branch.location === selectedLocation;
    });
  }, [selectedLocation]);

  const scrollToSection = useCallback((id: string) => {
    const element = document.getElementById(id);
    if (element) {
      const headerOffset = 80;
      const elementPosition = element.getBoundingClientRect().top;
      const offsetPosition = elementPosition + window.pageYOffset - headerOffset;

      window.scrollTo({
        top: offsetPosition,
        behavior: 'smooth'
      });

      setActiveSection(id);
      setIsMenuOpen(false);
      window.history.pushState(null, '', `#${id}`);
    }
  }, []);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const observerOptions = {
      root: null,
      rootMargin: '-85px 0px -70% 0px',
      threshold: 0
    };

    const handleIntersection = (entries: IntersectionObserverEntry[]) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          setActiveSection(entry.target.id);
        }
      });
    };

    const observer = new IntersectionObserver(handleIntersection, observerOptions);
    const sections = ['home', 'brands', 'services', 'locations', 'contact'];

    sections.forEach((id) => {
      const el = document.getElementById(id);
      if (el) observer.observe(el);
    });

    return () => observer.disconnect();
  }, []);

  const navItems = [
    { name: 'Home', id: 'home' },
    { name: 'Brands', id: 'brands' },
    { name: 'Services', id: 'services' },
    { name: 'Locations', id: 'locations' },
    { name: 'Contact', id: 'contact' }
